oxy_webhelp_navlinks = {"exocompute_for_aws-d30753e13746":{"topics":[{"title":"Introduction to Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">Describes common Exocompute terminology and a workflow example to\n                        help you plan and set up Exocompute on AWS.<\/p>","href":"saas\/aws_exocompute_workflow_example.html","menu":{"hasChildren":false},"tocID":"tocId-d30753e13763","next":"tocId-d30753e13763"},{"title":"Evaluate Exocompute on AWS options","shortdesc":"<p class=\"shortdesc\">When setting up Exocompute on AWS, it is important to evaluate the options for         deployment and networking. Thorough evaluation of these choices helps to align them with the         needs of your organization prior to Exocompute configuration.<\/p>","href":"saas\/aws_exocompute_evaluate_options.html","attributes":{"data-id":"aws_exocompute_evaluate_options"},"menu":{"hasChildren":false},"tocID":"aws_exocompute_evaluate_options-d30753e13789","next":"aws_exocompute_evaluate_options-d30753e13789"},{"title":"Prerequisites for Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">Before configuring Exocompute in AWS regions, ensure you have established a robust         network setup and addressed encryption key requirements to enable secure communication and         data protection.<\/p>","href":"saas\/aws_prereq_exocompute.html","attributes":{"data-id":"aws_prereq_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_prereq_exocompute-d30753e13855","next":"aws_prereq_exocompute-d30753e13855"},{"title":"Configure Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">The configuration workflow sequence for localized and centralized Exocompute on AWS,         Rubrik-hosted Elastic Container Registry, and Rubrik-managed Elastic Kubernetes Service         cluster.<\/p>","href":"saas\/aws_configuration_exocompute.html","attributes":{"data-id":"aws_configuration_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_configuration_exocompute-d30753e14081","next":"aws_configuration_exocompute-d30753e14081"},{"title":"Private Container Registry for AWS","shortdesc":"<p class=\"shortdesc\">For security purposes, when you do not want to retrieve Docker images from a registry         hosted by Rubrik, you can configure a Private Container Registry to retrieve these Docker         images from a registry hosted by you.<\/p>","href":"saas\/private_container_registry.html","attributes":{"data-id":"private_container_registry"},"menu":{"hasChildren":false},"tocID":"private_container_registry-d30753e14170","next":"private_container_registry-d30753e14170"},{"title":"Exocompute health check for AWS","shortdesc":"<p class=\"shortdesc\">The Exocompute health check for AWS is a feature in <span class=\"ph\">RSC<\/span> that runs a         health check for an Elastic Kubernetes Service cluster immediately after its configuration         and displays the relevant status.<\/p>","href":"saas\/aws_exocompute_health_check.html","attributes":{"data-id":"aws_exocompute_health_check"},"menu":{"hasChildren":false},"tocID":"aws_exocompute_health_check-d30753e14203","next":"aws_exocompute_health_check-d30753e14203"},{"title":"Viewing Exocompute events","shortdesc":"<p class=\"shortdesc\">View the Events page from the Dashboard to see the Exocompute events.<\/p>","href":"saas\/viewing_exo_health_check_events.html","attributes":{"data-id":"viewing_exo_health_check_events"},"menu":{"hasChildren":false},"tocID":"viewing_exo_health_check_events-d30753e14228","next":"viewing_exo_health_check_events-d30753e14228"},{"title":"Maintain Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">Maintaining Exocompute on AWS involves regularly reviewing and updating settings and         removing obsolete configurations to ensure optimal performance and resource         management.<\/p>","href":"saas\/aws_maintenance_exocompute.html","attributes":{"data-id":"aws_maintenance_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_maintenance_exocompute-d30753e14250","next":"aws_maintenance_exocompute-d30753e14250"},{"title":"Best practices for reducing Exocompute on AWS costs","shortdesc":"<p class=\"shortdesc\">You can configure your AWS network and storage settings to avoid unexpected costs         when using Exocompute on AWS for archiving and data protection operations.<\/p>","href":"saas\/aws_exo_cost_best_practices.html","attributes":{"data-id":"aws_exo_cost_best_practices"},"menu":{"hasChildren":false},"tocID":"aws_exo_cost_best_practices-d30753e14305","next":"aws_exo_cost_best_practices-d30753e14305"}]}};